// Helper function for recursive factorization.
// Tries divisors starting from 'divisor' and recursively counts factors.
static unsigned int
count_factors_recursive_helper(unsigned int n, unsigned int divisor)
{
	// Base case: if divisor squared is greater than n,
	// then n is either 1 or a prime factor itself
	if (divisor * divisor > n) {
		return (n > 1 ? 1 : 0);
	}

	// If n is divisible by divisor, divide it out and count
	if (n % divisor == 0) {
		return (1 + count_factors_recursive_helper(n / divisor, divisor));
	}

	// Otherwise, try the next divisor
	return (count_factors_recursive_helper(n, divisor + 1));
}

