/*
 * Requires:
 *   The input "n" must be greater than 1.
 *
 * Effects:
 *   Returns the number of factors of the input "n".
 */
static unsigned int
count_factors(unsigned int n)
{
	unsigned int count = 0;
	unsigned int divisor = 2;

	assert(n > 1);

	// Try divisors starting from 2
	while (divisor * divisor <= n) {
		// Divide out all occurrences of this divisor
		while (n % divisor == 0) {
			count++;
			n /= divisor;
		}

		// Move to next divisor
		if (divisor == 2) {
			divisor = 3;
		} else {
			divisor += 2;  // Skip even numbers after 2
		}
	}

	// If n is still greater than 1, it's a prime factor
	if (n > 1) {
		count++;
	}

	return (count);
}

